"use client";
import * as React from "react";
import { paginationAnatomy, paginationRange } from "@tessera/core";
import { useControllableState } from "../utils/hooks";

export interface PaginationProps {
  /** Total number of pages. */
  count: number;
  page?: number;
  defaultPage?: number;
  onPageChange?: (page: number) => void;
  /** Pages shown on each side of the current page. Default 1. */
  siblings?: number;
}

export function Pagination({
  count,
  page,
  defaultPage = 1,
  onPageChange,
  siblings = 1,
}: PaginationProps) {
  const [current, setPage] = useControllableState({
    value: page,
    defaultValue: defaultPage,
    onChange: onPageChange,
  });
  const entries = paginationRange(current, count, siblings);

  return (
    <nav {...paginationAnatomy.attrs("root")} aria-label="Pagination">
      <ul {...paginationAnatomy.attrs("list")}>
        <li>
          <button
            type="button"
            {...paginationAnatomy.attrs("prev")}
            aria-label="Previous page"
            disabled={current <= 1}
            onClick={() => setPage(current - 1)}
          >
            ‹
          </button>
        </li>
        {entries.map((entry, index) =>
          entry === "ellipsis" ? (
            <li key={`ellipsis-${index}`}>
              <span {...paginationAnatomy.attrs("ellipsis")} aria-hidden>
                …
              </span>
            </li>
          ) : (
            <li key={entry}>
              <button
                type="button"
                {...paginationAnatomy.attrs("item")}
                aria-label={`Page ${entry}`}
                aria-current={entry === current ? "page" : undefined}
                onClick={() => setPage(entry)}
              >
                {entry}
              </button>
            </li>
          )
        )}
        <li>
          <button
            type="button"
            {...paginationAnatomy.attrs("next")}
            aria-label="Next page"
            disabled={current >= count}
            onClick={() => setPage(current + 1)}
          >
            ›
          </button>
        </li>
      </ul>
    </nav>
  );
}

@layer tessera.recipes {
  [data-scope="pagination"][data-part="list"] {
    display: flex;
    align-items: center;
    gap: var(--ts-space-1);
    margin: 0;
    padding: 0;
    list-style: none;
  }

  [data-scope="pagination"][data-part="item"],
  [data-scope="pagination"][data-part="prev"],
  [data-scope="pagination"][data-part="next"] {
    appearance: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 2rem;
    height: 2rem;
    padding: 0 var(--ts-space-2);
    border: 1px solid transparent;
    border-radius: var(--ts-radius-md);
    background: transparent;
    color: var(--ts-fg-muted);
    font-size: var(--ts-font-size-sm);
    font-variant-numeric: tabular-nums;
    cursor: pointer;
  }

  [data-scope="pagination"] [data-part="item"]:hover:not(:disabled),
  [data-scope="pagination"] [data-part="prev"]:hover:not(:disabled),
  [data-scope="pagination"] [data-part="next"]:hover:not(:disabled) {
    background: var(--ts-bg-subtle);
    color: var(--ts-fg-default);
  }

  [data-scope="pagination"][data-part="item"][aria-current="page"] {
    background: var(--ts-accent-default);
    border-color: var(--ts-accent-default);
    color: var(--ts-fg-onAccent);
    font-weight: var(--ts-font-weight-semibold);
  }

  [data-scope="pagination"][data-part="ellipsis"] {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 2rem;
    height: 2rem;
    color: var(--ts-fg-subtle);
    user-select: none;
  }
}
